### 4. Normal State (with score)
```tsx
interface SpeedScoreBadgeProps {
  score: number | null | undefined;
  previousScore?: number | null;
  size?: 'sm' | 'md' | 'lg';
  showTrend?: boolean;
  isLoading?: boolean;
  error?: Error | null;
  onRetry?: () => void;
}

const SpeedScoreBadge: React.FC<SpeedScoreBadgeProps> = ({
  score,
  previousScore,
  size = 'md',
  showTrend = true,
  isLoading = false,
  error = null,
  onRetry,
}) => {
  // Handle loading state
  if (isLoading) {
    return <SpeedScoreBadgeSkeleton size={size} />;
  }

  // Handle error state
  if (error) {
    return <SpeedScoreBadgeError error={error} onRetry={onRetry} />;
  }

  // Handle not-benchmarked state
  if (score === null || score === undefined) {
    return <SpeedScoreBadgeEmpty />;
  }

  // Normal rendering
  const colorClass = getScoreColorClass(score);
  const trend = previousScore != null ? calculateTrend(score, previousScore) : null;

  return (
    <div 
      className={cn('speedscore-badge', size, colorClass)}
      role="status"
      aria-label={`SpeedScore: ${score.toFixed(0)} out of 100, ${getScoreLabel(score)}`}
    >
      <span className="score-value">{score.toFixed(0)}</span>
      {showTrend && trend && (
        <TrendIndicator 
          direction={trend.direction} 
          magnitude={trend.magnitude}
          delta={trend.delta}
        />
      )}
    </div>
  );
};
```

## Color Coding
```typescript
type ScoreLevel = 'excellent' | 'good' | 'average' | 'below_average' | 'poor';

const SCORE_LEVELS: Record<ScoreLevel, { min: number; max: number; color: string; label: string }> = {
  excellent:     { min: 90, max: 100, color: '#22c55e', label: 'Excellent' },
  good:          { min: 70, max: 89,  color: '#3b82f6', label: 'Good' },
  average:       { min: 50, max: 69,  color: '#eab308', label: 'Average' },
  below_average: { min: 30, max: 49,  color: '#f97316', label: 'Below Average' },
  poor:          { min: 0,  max: 29,  color: '#ef4444', label: 'Poor' },
};

function getScoreColorClass(score: number): string {
  for (const [level, config] of Object.entries(SCORE_LEVELS)) {
    if (score >= config.min && score <= config.max) {
      return `score-${level}`;
    }
  }
  return 'score-unknown';
}

function getScoreLabel(score: number): string {
  for (const config of Object.values(SCORE_LEVELS)) {
    if (score >= config.min && score <= config.max) {
      return config.label;
    }
  }
  return 'Unknown';
}
```

## Trend Indicator
```tsx
interface TrendIndicatorProps {
  direction: 'up' | 'down' | 'stable';
  magnitude: 'small' | 'medium' | 'large';  // <5%, 5-15%, >15%
  delta: number;  // Actual point difference
}

const TrendIndicator: React.FC<TrendIndicatorProps> = ({
  direction,
  magnitude,
  delta,
}) => {
  const icons = {
    up: { small: '↗', medium: '↑', large: '⬆' },
    down: { small: '↘', medium: '↓', large: '⬇' },
    stable: { small: '→', medium: '→', large: '→' },
  };

  const colors = {
    up: 'text-green-500',
    down: 'text-red-500',
    stable: 'text-gray-400',
  };

  return (
    <Tooltip content={`${delta > 0 ? '+' : ''}${delta.toFixed(1)} since last benchmark`}>
      <span 
        className={cn('trend-indicator', colors[direction], `magnitude-${magnitude}`)}
        aria-label={`Trend: ${direction}, ${Math.abs(delta).toFixed(1)} points`}
      >
        {icons[direction][magnitude]}
      </span>
    </Tooltip>
  );
};

function calculateTrend(current: number, previous: number): {
  direction: 'up' | 'down' | 'stable';
  magnitude: 'small' | 'medium' | 'large';
  delta: number;
} {
  const delta = current - previous;
  const percentChange = Math.abs(delta / previous) * 100;

  let direction: 'up' | 'down' | 'stable';
  if (Math.abs(delta) < 1) {
    direction = 'stable';
  } else {
    direction = delta > 0 ? 'up' : 'down';
  }

  let magnitude: 'small' | 'medium' | 'large';
  if (percentChange < 5) {
    magnitude = 'small';
  } else if (percentChange < 15) {
    magnitude = 'medium';
  } else {
    magnitude = 'large';
  }

  return { direction, magnitude, delta };
}
```

